window.iconPickerVue=new Vue({el:"#iconPickerVue",data:function(){return{targetInputField:"",targetIconTag:"",iconPickerModal:null}},mounted:function(){$(".icp-auto").iconpicker({title:!1,templates:{search:'<input type="search" class="form-control iconpicker-search" placeholder="" />'}}),$("#inline-picker").on("iconpickerSelected",e=>{var t=e.iconpickerInstance.options.fullClassFormatter(e.iconpickerValue);if(this.targetInputField&&(document.getElementById(this.targetInputField).value=t),this.targetIconTag){var i=document.createElement("i");i.id=this.targetIconTag,i.className=t,document.getElementById(this.targetIconTag).replaceWith(i)}null!=this.iconPickerModal&&this.iconPickerModal.hide()})},methods:{show:function(e,t){this.targetInputField=e,this.targetIconTag=t,null==this.iconPickerModal&&(this.iconPickerModal=new bootstrap.Modal(document.getElementById("iconPickerModal"),{keyboard:!1})),this.iconPickerModal.show()}}});
